// Parser le payload
const raw = $input.item.json;
const payload = raw?.body || raw;
const event = payload?.event || 'unknown';
const data = payload?.data || {};

// Emojis par type
const emojis = {
  'lead.created': '\u{1F195}',
  'lead.status_changed': '\u{1F504}',
  'lead.deleted': '\u{1F5D1}',
  'lead.converted': '\u{1F389}',
  'client.created': '\u{1F464}',
  'client.updated': '\u{270F}',
  'client.deleted': '\u{274C}'
};

const emoji = emojis[event] || '\u{1F4E2}';
let message = '';

switch (event) {
  case 'lead.created':
    message = emoji + ' Nouveau lead\n\nNom: ' + (data.firstName || '') + ' ' + (data.lastName || '') + '\nEmail: ' + (data.email || 'N/A') + '\nTelephone: ' + (data.phone || 'N/A') + '\nSource: ' + (data.source || 'N/A');
    break;
  case 'lead.status_changed':
    message = emoji + ' Lead mis a jour\n\nNom: ' + (data.firstName || '') + ' ' + (data.lastName || '') + '\nStatut: ' + (data.oldStatus || '?') + ' -> ' + (data.newStatus || '?');
    break;
  case 'lead.deleted':
    message = emoji + ' Lead supprime\n\nNom: ' + (data.firstName || '') + ' ' + (data.lastName || '') + '\nEmail: ' + (data.email || 'N/A');
    break;
  case 'lead.converted':
    message = emoji + ' Lead converti en client !\n\nNom: ' + (data.firstName || '') + ' ' + (data.lastName || '') + '\nEmail: ' + (data.email || 'N/A');
    break;
  case 'client.created':
    message = emoji + ' Nouveau client\n\nNom: ' + (data.name || data.company || 'N/A') + '\nEmail: ' + (data.email || 'N/A') + '\nTelephone: ' + (data.phone || 'N/A');
    break;
  case 'client.updated':
    message = emoji + ' Client mis a jour\n\nNom: ' + (data.name || data.company || 'N/A') + '\nChamps: ' + (Array.isArray(data.updatedFields) ? data.updatedFields.join(', ') : 'N/A');
    break;
  case 'client.deleted':
    message = emoji + ' Client supprime\n\nNom: ' + (data.name || data.company || 'N/A') + '\nEmail: ' + (data.email || 'N/A');
    break;
  default:
    message = '\u{1F4E2} Evenement: ' + event + '\n\n' + JSON.stringify(data, null, 2).substring(0, 500);
}

return [{ json: { message: message, event: event, chatId: payload?.chatId || '6296082748' } }];
